    uint8_t downlinkLQ;  // Downlink Link Quality (0-100) | units: %
    uint8_t uplinkLQ;  // Uplink Link Quality (0-100) | units: %
    int8_t uplinkSNR;  // Uplink Signal-to-Noise Ratio | units: dB
